module verified_binary_counter(reset, load, data, count);

    input reset;
    input load;
    input [3:0] data;
    output [3:0] count;
    reg [3:0] count;
    initial count = 0;

    always @(posedge reset)
        begin
            if (load)
                count <= data;
            else
                count <= count + 1;
        end

endmodule
